package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  private static class DummyClass {
    private String field;
  }

  private Field dummyField;

  @BeforeEach
  void setUp() throws NoSuchFieldException {
    dummyField = DummyClass.class.getDeclaredField("field");
  }

  @Test
  void testGetAccessor_delegatesToRecordHelper() throws Exception {
    Method expectedMethod = DummyClass.class.getDeclaredMethod("toString");

    // Create a mock of the RecordHelper class via reflection
    Class<?> recordHelperClass = Class.forName("com.google.gson.internal.reflect.RecordHelper");
    Object recordHelperMock = mock(recordHelperClass);

    // Stub the getAccessor method on the mock via reflection
    Method getAccessorMethod = recordHelperClass.getMethod("getAccessor", Class.class, Field.class);
    when(getAccessorMethod.invoke(recordHelperMock, DummyClass.class, dummyField)).thenThrow(new IllegalStateException("Should not call invoke directly"));

    // Instead, use Mockito's doAnswer to stub the method properly
    // Use Mockito's doReturn with reflection proxy:
    // We need to stub the actual method call, so use Mockito's when() on the proxy object via a cast

    // Cast recordHelperMock to the recordHelperClass type
    Object proxy = recordHelperMock;

    // Use Mockito's doReturn().when() with reflection proxy:
    // Since recordHelperMock is an Object, we need to use Mockito's 'mock' with 'withSettings' and 'defaultAnswer' or use a proxy subclass.

    // The simpler way is to create a proxy subclass with Mockito that returns expectedMethod when getAccessor is called:

    // Create a Mockito spy with Answers:
    Object spy = mock(recordHelperClass, invocation -> {
      if (invocation.getMethod().getName().equals("getAccessor")
          && invocation.getMethod().getParameterCount() == 2
          && invocation.getMethod().getParameterTypes()[0] == Class.class
          && invocation.getMethod().getParameterTypes()[1] == Field.class) {
        return expectedMethod;
      }
      return invocation.callRealMethod();
    });

    // Set the private static final RECORD_HELPER field in ReflectionHelper to the spy mock
    java.lang.reflect.Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    java.lang.reflect.Field modifiersField = java.lang.reflect.Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    recordHelperField.set(null, spy);

    // Call the method under test
    Method actualMethod = ReflectionHelper.getAccessor(DummyClass.class, dummyField);

    // Assert the returned method is the expected one
    assertSame(expectedMethod, actualMethod);

    // Verify the mock's getAccessor method was called with the correct arguments
    verify(spy).getAccessor(DummyClass.class, dummyField);
  }
}
